#!/usr/bin/env node
/*
 * Re-apply the Android release (upload) signing config after `expo prebuild`.
 *
 * `android/` is CNG (gitignored, regenerated by prebuild), so the release
 * signingConfig must be re-injected each time. The keystore + passwords live in
 * the repo-root `credentials/` folder (outside android/, gitignored) and survive
 * prebuild; this script only edits android/app/build.gradle. Idempotent — safe to
 * run from `postinstall` (it no-ops when android/ or the marker is absent/present).
 *
 * Run manually after a prebuild:  node scripts/patch-android-signing.js
 */
const fs = require('fs');
const path = require('path');

const gradle = path.join(__dirname, '..', 'android', 'app', 'build.gradle');
if (!fs.existsSync(gradle)) process.exit(0); // managed / not prebuilt yet

let src = fs.readFileSync(gradle, 'utf8');
if (src.includes('releaseKeystoreProps')) process.exit(0); // already patched

const DEFAULT_SIGNING = `    signingConfigs {
        debug {
            storeFile file('debug.keystore')
            storePassword 'android'
            keyAlias 'androiddebugkey'
            keyPassword 'android'
        }
    }`;

const PATCHED_SIGNING = `    // Load the release (upload) keystore from credentials/keystore.properties at
    // the project root — kept OUTSIDE android/ so \`expo prebuild\` doesn't wipe it,
    // and gitignored. If absent, release falls back to the debug key (dev only).
    def releaseKeystoreProps = new Properties()
    def releaseKeystoreFile = rootProject.file('../credentials/keystore.properties')
    if (releaseKeystoreFile.exists()) {
        releaseKeystoreFile.withInputStream { releaseKeystoreProps.load(it) }
    }

    signingConfigs {
        debug {
            storeFile file('debug.keystore')
            storePassword 'android'
            keyAlias 'androiddebugkey'
            keyPassword 'android'
        }
        if (releaseKeystoreProps['storeFile']) {
            release {
                storeFile rootProject.file(releaseKeystoreProps['storeFile'])
                storePassword releaseKeystoreProps['storePassword']
                keyAlias releaseKeystoreProps['keyAlias']
                keyPassword releaseKeystoreProps['keyPassword']
            }
        }
    }`;

if (!src.includes(DEFAULT_SIGNING)) {
  console.warn('[patch-android-signing] default signingConfigs block not found — skipping (was the template changed?)');
  process.exit(0);
}
src = src.replace(DEFAULT_SIGNING, PATCHED_SIGNING);

// Point the release buildType at the upload key when present (else debug).
src = src.replace(
  /signingConfig signingConfigs\.debug(\s*\n\s*def enableShrinkResources)/,
  "signingConfig releaseKeystoreProps['storeFile'] ? signingConfigs.release : signingConfigs.debug$1"
);

fs.writeFileSync(gradle, src);
console.log('[patch-android-signing] release signing config injected into android/app/build.gradle');
